import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import axios from 'axios';

export default function FacultyDashboard() {
  const { user, API } = useAuth();
  const { dark } = useTheme();
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [requests, setRequests] = useState([]);
  const [notifs, setNotifs]     = useState([]);
  const [loading, setLoading]   = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving]     = useState(false);
  const [msg, setMsg]           = useState('');
  const [form, setForm] = useState({title:'',description:'',requiredSkills:'',duration:'',maxStudents:5});

  const bg=dark?'#0a0d14':'#f4f6fb', card=dark?'#161c2e':'#ffffff', border=dark?'#252d47':'#e2e8f0';
  const text=dark?'#e8eaf0':'#1a1a2e', muted=dark?'#9aa3bf':'#64748b', sub=dark?'#5c6580':'#94a3b8';
  const h=()=>({headers:{Authorization:`Bearer ${localStorage.getItem('token')}`},timeout:15000});

  const load = async () => {
    setLoading(true);
    try {
      const [pRes, rRes, nRes] = await Promise.all([
        axios.get(`${API}/projects/my`, h()),
        axios.get(`${API}/requests/my`, h()),
        axios.get(`${API}/notifications`, h()),
      ]);
      setProjects(pRes.data);
      setRequests(rRes.data);
      setNotifs(nRes.data.filter(n=>!n.read).slice(0,3));
    } catch {}
    setLoading(false);
  };

  useEffect(()=>{ load(); },[API]);

  const handleCreate = async () => {
    if (!form.title.trim()||!form.description.trim()) { setMsg('❌ Title and description required'); return; }
    setSaving(true);
    try {
      await axios.post(`${API}/projects`,{...form,requiredSkills:form.requiredSkills.split(',').map(x=>x.trim()).filter(Boolean),maxStudents:Number(form.maxStudents)||5},h());
      setShowForm(false);
      setForm({title:'',description:'',requiredSkills:'',duration:'',maxStudents:5});
      setMsg('✅ Project created!');
      setTimeout(()=>setMsg(''),3000);
      load();
    } catch(err){ setMsg('❌ '+(err.response?.data?.message||'Failed')); }
    setSaving(false);
  };

  const handleToggle = async (p) => {
    try {
      const ns=p.status==='open'?'closed':'open';
      await axios.put(`${API}/projects/${p._id}`,{status:ns},h());
      setProjects(prev=>prev.map(x=>x._id===p._id?{...x,status:ns}:x));
    } catch { alert('Failed'); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this project?')) return;
    try { await axios.delete(`${API}/projects/${id}`,h()); setProjects(prev=>prev.filter(p=>p._id!==id)); } catch { alert('Failed'); }
  };

  const handleRequest = async (id, status) => {
    try {
      await axios.put(`${API}/requests/${id}`,{status},h());
      setRequests(prev=>prev.map(r=>r._id===id?{...r,status}:r));
    } catch { alert('Failed'); }
  };

  const pending  = requests.filter(r=>r.status==='pending');
  const accepted = requests.filter(r=>r.status==='accepted');

  if (loading) return <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'60vh',color:'#6c63ff'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',background:bg,padding:'1.5rem',fontFamily:'system-ui,sans-serif'}}>
      <div style={{maxWidth:960,margin:'0 auto'}}>

        {/* Header */}
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1.5rem',flexWrap:'wrap',gap:'0.75rem'}}>
          <div>
            <h1 style={{fontWeight:800,fontSize:'1.4rem',color:text,marginBottom:'0.2rem'}}>Hi, {user.name.split(' ')[0]} 👋</h1>
            <p style={{color:muted,fontSize:'0.85rem'}}>{user.designation||'Faculty'} · {user.department}</p>
          </div>
          <button onClick={()=>setShowForm(true)} style={{padding:'9px 18px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:9,color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.85rem'}}>+ New Project</button>
        </div>

        {msg && <div style={{background:msg.includes('✅')?'rgba(34,197,94,0.1)':'rgba(239,68,68,0.1)',border:`1px solid ${msg.includes('✅')?'#22c55e40':'#ef444440'}`,borderRadius:9,padding:'10px',marginBottom:'1rem',color:msg.includes('✅')?'#22c55e':'#ef4444',fontSize:'0.85rem'}}>{msg}</div>}

        {/* Alerts */}
        {notifs.length>0 && (
          <div style={{marginBottom:'1.5rem'}}>
            {notifs.map(n=>(
              <div key={n._id} onClick={()=>navigate('/notifications')} style={{background:dark?'rgba(108,99,255,0.08)':'#f0eeff',border:`1px solid ${dark?'#6c63ff30':'#c4bbff'}`,borderRadius:9,padding:'0.7rem 1rem',marginBottom:'0.4rem',cursor:'pointer',display:'flex',gap:'0.75rem',alignItems:'center'}}>
                <span>🔔</span><span style={{fontSize:'0.85rem',color:text,flex:1}}>{n.message}</span><span style={{fontSize:'0.7rem',color:sub}}>new</span>
              </div>
            ))}
            <Link to="/notifications" style={{fontSize:'0.78rem',color:'#6c63ff',fontWeight:600,textDecoration:'none'}}>View all →</Link>
          </div>
        )}

        {/* Stats */}
        <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'0.75rem',marginBottom:'1.5rem'}}>
          {[
            {label:'My Projects',  value:projects.length,              color:'#6c63ff'},
            {label:'Open',         value:projects.filter(p=>p.status==='open').length, color:'#22c55e'},
            {label:'Pending',      value:pending.length,               color:'#f59e0b'},
            {label:'Accepted',     value:accepted.length,              color:'#00d4aa'},
          ].map((s,i)=>(
            <div key={i} style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'1rem',textAlign:'center'}}>
              <div style={{fontSize:'1.6rem',fontWeight:800,color:s.color,lineHeight:1}}>{s.value}</div>
              <div style={{fontSize:'0.75rem',color:muted,marginTop:'0.3rem'}}>{s.label}</div>
            </div>
          ))}
        </div>

        {/* Pending requests */}
        {pending.length>0 && (
          <div style={{marginBottom:'1.5rem'}}>
            <h2 style={{fontWeight:700,fontSize:'0.95rem',color:text,marginBottom:'0.75rem'}}>📬 Pending Applications <span style={{background:'#f59e0b20',color:'#f59e0b',borderRadius:99,padding:'1px 8px',fontSize:'0.75rem',marginLeft:'6px'}}>{pending.length}</span></h2>
            <div style={{display:'flex',flexDirection:'column',gap:'0.5rem'}}>
              {pending.map(r=>(
                <div key={r._id} style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'1rem',display:'flex',alignItems:'center',gap:'1rem',flexWrap:'wrap'}}>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:700,fontSize:'0.875rem',color:text}}>{r.student?.name}</div>
                    <div style={{fontSize:'0.75rem',color:muted}}>{r.student?.department} · {r.student?.year}</div>
                    <div style={{fontSize:'0.78rem',color:'#6c63ff',marginTop:'0.2rem'}}>for: {r.project?.title}</div>
                  </div>
                  <div style={{display:'flex',gap:'0.5rem'}}>
                    <button onClick={()=>handleRequest(r._id,'accepted')} style={{padding:'6px 14px',borderRadius:7,background:'rgba(34,197,94,0.1)',border:'1px solid #22c55e40',color:'#22c55e',fontWeight:700,fontSize:'0.78rem',cursor:'pointer'}}>✓ Accept</button>
                    <button onClick={()=>handleRequest(r._id,'rejected')} style={{padding:'6px 14px',borderRadius:7,background:'rgba(239,68,68,0.1)',border:'1px solid #ef444440',color:'#ef4444',fontWeight:700,fontSize:'0.78rem',cursor:'pointer'}}>✗ Reject</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* My Projects */}
        <div>
          <h2 style={{fontWeight:700,fontSize:'0.95rem',color:text,marginBottom:'0.75rem'}}>🗂 My Projects</h2>
          {projects.length===0 ? (
            <div style={{background:card,border:`1px solid ${border}`,borderRadius:12,padding:'3rem',textAlign:'center'}}>
              <div style={{color:sub,fontSize:'0.875rem',marginBottom:'1rem'}}>No projects yet</div>
              <button onClick={()=>setShowForm(true)} style={{padding:'9px 20px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:9,color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.85rem'}}>Create First Project</button>
            </div>
          ) : (
            <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:'0.75rem'}}>
              {projects.map(p=>{
                const pp=requests.filter(r=>r.project?._id===p._id&&r.status==='pending').length;
                return (
                  <div key={p._id} style={{background:card,border:`1px solid ${p.status==='open'?'#22c55e30':border}`,borderRadius:12,padding:'1.1rem'}}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'0.6rem'}}>
                      <h3 style={{fontWeight:700,fontSize:'0.875rem',color:text,flex:1,marginRight:'0.5rem',lineHeight:1.3}}>{p.title}</h3>
                      <span style={{padding:'2px 8px',borderRadius:99,fontSize:'0.65rem',fontWeight:700,background:p.status==='open'?'rgba(34,197,94,0.1)':'rgba(239,68,68,0.1)',color:p.status==='open'?'#22c55e':'#ef4444',border:`1px solid ${p.status==='open'?'#22c55e40':'#ef444440'}`,flexShrink:0}}>{p.status}</span>
                    </div>
                    {pp>0 && <div style={{fontSize:'0.75rem',color:'#f59e0b',marginBottom:'0.6rem',fontWeight:600}}>⏳ {pp} pending application{pp>1?'s':''}</div>}
                    <div style={{display:'flex',gap:'0.4rem',flexWrap:'wrap'}}>
                      <button onClick={()=>navigate(`/projects/${p._id}`)} style={{padding:'5px 11px',borderRadius:6,background:'rgba(108,99,255,0.1)',border:'1px solid #6c63ff30',color:'#6c63ff',fontSize:'0.72rem',fontWeight:600,cursor:'pointer'}}>Manage</button>
                      <button onClick={()=>handleToggle(p)} style={{padding:'5px 11px',borderRadius:6,background:'transparent',border:`1px solid ${border}`,color:muted,fontSize:'0.72rem',cursor:'pointer'}}>{p.status==='open'?'Close':'Open'}</button>
                      <button onClick={()=>handleDelete(p._id)} style={{padding:'5px 11px',borderRadius:6,background:'transparent',border:`1px solid ${border}`,color:sub,fontSize:'0.72rem',cursor:'pointer'}}>Delete</button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Create Modal */}
      {showForm && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.6)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000,padding:'1rem'}}>
          <div style={{background:card,border:`1px solid ${border}`,borderRadius:14,padding:'1.75rem',width:'100%',maxWidth:480,maxHeight:'90vh',overflowY:'auto'}}>
            <div style={{display:'flex',justifyContent:'space-between',marginBottom:'1.25rem'}}>
              <h2 style={{fontWeight:800,fontSize:'1.1rem',color:text}}>+ New Project</h2>
              <button onClick={()=>setShowForm(false)} style={{background:'transparent',border:'none',color:muted,fontSize:'1.3rem',cursor:'pointer'}}>✕</button>
            </div>
            {[
              {label:'Title *',key:'title',ph:'e.g. AI-based Crop Disease Detection'},
              {label:'Description *',key:'description',ph:'Describe the project...',area:true},
              {label:'Required Skills (comma separated)',key:'requiredSkills',ph:'Python, ML, OpenCV'},
              {label:'Duration',key:'duration',ph:'e.g. 3 months'},
            ].map(f=>(
              <div key={f.key} style={{marginBottom:'0.875rem'}}>
                <label style={{display:'block',marginBottom:'5px',fontSize:'0.8rem',fontWeight:600,color:muted}}>{f.label}</label>
                {f.area
                  ? <textarea value={form[f.key]} onChange={e=>setForm(x=>({...x,[f.key]:e.target.value}))} placeholder={f.ph} rows={3} style={{width:'100%',padding:'9px 12px',background:bg,border:`1px solid ${border}`,borderRadius:8,color:text,fontSize:'0.875rem',outline:'none',boxSizing:'border-box',resize:'vertical'}} />
                  : <input value={form[f.key]} onChange={e=>setForm(x=>({...x,[f.key]:e.target.value}))} placeholder={f.ph} style={{width:'100%',padding:'9px 12px',background:bg,border:`1px solid ${border}`,borderRadius:8,color:text,fontSize:'0.875rem',outline:'none',boxSizing:'border-box'}} />
                }
              </div>
            ))}
            <div style={{marginBottom:'1.25rem'}}>
              <label style={{display:'block',marginBottom:'5px',fontSize:'0.8rem',fontWeight:600,color:muted}}>Max Students</label>
              <input type="number" min={1} max={20} value={form.maxStudents} onChange={e=>setForm(x=>({...x,maxStudents:e.target.value}))} style={{width:'100%',padding:'9px 12px',background:bg,border:`1px solid ${border}`,borderRadius:8,color:text,fontSize:'0.875rem',outline:'none',boxSizing:'border-box'}} />
            </div>
            <div style={{display:'flex',gap:'0.6rem'}}>
              <button onClick={()=>setShowForm(false)} style={{flex:1,padding:'10px',background:'transparent',border:`1px solid ${border}`,borderRadius:9,color:muted,fontWeight:600,cursor:'pointer',fontSize:'0.85rem'}}>Cancel</button>
              <button onClick={handleCreate} disabled={saving} style={{flex:2,padding:'10px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:9,color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.85rem'}}>{saving?'Creating...':'Create Project'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
